t.script:
(function() {
    var liffId = '';
    var target = '';

    if (!liffId) {
        console.error('LIFF ID 未設定');
        return;
    }

    liff.init({ liffId: liffId }).then(function() {
        if (!liff.isLoggedIn()) {
            liff.login({ redirectUri: window.location.href });
            return;
        }

        liff.getIDToken().then(function(idToken) {
            if (!idToken) {
                console.error('無法取得 ID Token');
                return;
            }

            // POST ID Token 到 redirect endpoint
            var form = document.createElement('form');
            form.method = 'POST';
            form.action = window.location.pathname;

            var input = document.createElement('input');
            input.type = 'hidden';
            input.name = 'id_token';
            input.value = idToken;
            form.appendChild(input);

            document.body.appendChild(form);
            form.submit();
        }).catch(function(err) {
            // getIDToken 可能不是 Promise 在某些版本
            var idToken = liff.getIDToken();
            if (idToken) {
                var form = document.createElement('form');
                form.method = 'POST';
                form.action = window.location.pathname;

                var input = document.createElement('input');
                input.type = 'hidden';
                input.name = 'id_token';
                input.value = idToken;
                form.appendChild(input);

                document.body.appendChild(form);
                form.submit();
            } else {
                console.error('getIDToken 失敗', err);
            }
        });
    }).catch(function(err) {
        console.error('LIFF init 失敗', err);
    });
})();
